function findPairs(sortedArray, target):
    left = 0
    right = length(sortedArray) - 1
    pairs = []

    while left < right:
        currentSum = sortedArray[left] + sortedArray[right]

        if currentSum == target:
            pairs.add((sortedArray[left], sortedArray[right]))
            left += 1
            right -= 1
        else if currentSum < target:
            left += 1
        else:
            right -= 1

    return pairs

/**
 * @param {number[][]} matrix
 * @param {number} k
 * @return {number}
 */
function kthSmallestElement(matrix, k) {
  const rows = matrix.length;
  if (rows === 0) return -1;
  const cols = matrix[0].length;

  // Guard clause for k out of bounds
  if (k > rows * cols) return -1;

  // Min-heap to store: [value, row_index, col_index]
  const minHeap = new MinPriorityQueue({ priority: x => x[0] });

  // 1. Push the first element of every row into the heap
  for (let r = 0; r < Math.min(rows, k); r++) {
    if (matrix[r].length > 0) {
      minHeap.enqueue([matrix[r][0], r, 0]);
    }
  }

  let count = 0;
  let result = -1;

  // 2. Extract min k times
  while (!minHeap.isEmpty() && count < k) {
    const [val, r, c] = minHeap.dequeue().element;
    result = val;
    count++;

    // 3. If there is a next element in the same row, push it
    if (c + 1 < matrix[r].length) {
      minHeap.enqueue([matrix[r][c + 1], r, c + 1]);
    }
  }

  return result;
}
